const item = $input.first();
const json = item.json ?? {};
const body = json.body ?? json;
const normalize = (v) => String(v ?? '').trim();

const accessToken = normalize(body.access_token);
const pageId = normalize(body.page_id);
const title = normalize(body.title || 'Reel publicitario');
const description = normalize(body.description || body.post_text || body.caption || '');

const binaryKeys = Object.keys(item.binary || {});
const hasBinary = binaryKeys.length > 0;
const binaryKey = binaryKeys[0] || '';
const fileSize = hasBinary && binaryKey ? (item.binary[binaryKey].fileSize || 0) : 0;

if (!accessToken) throw new Error('Se requiere access_token');
if (!pageId) throw new Error('Se requiere page_id');
if (!hasBinary) throw new Error('Se requiere un archivo de video');

const result = { json: { accessToken, pageId, title, description, hasBinary, binaryKey, fileSize } };
if (hasBinary && binaryKey) {
  result.binary = {};
  result.binary.video = item.binary[binaryKey];
}
return [result];

const response = $input.first().json;
const parsedData = $('Parsear Request').first().json;
const videoId = String(response.video_id || '').trim();
const uploadUrl = String(response.upload_url || '').trim();
if (!videoId || !uploadUrl) throw new Error('Facebook no devolvio video_id o upload_url: ' + JSON.stringify(response));

const parsedBinary = $('Parsear Request').first().binary;
let fileSize = Number(parsedData.fileSize || 0);
if (!fileSize && parsedBinary && parsedBinary.video) {
  const b = parsedBinary.video;
  if (b.fileSize) { fileSize = Number(b.fileSize); }
  else if (typeof b.data === 'string') { fileSize = Math.floor(b.data.length * 3 / 4); }
}

const result = {
  json: {
    videoId,
    uploadUrl,
    accessToken: parsedData.accessToken,
    pageId: parsedData.pageId,
    title: parsedData.title,
    description: parsedData.description,
    fileSize: fileSize,
  }
};
if (parsedBinary && parsedBinary.video) {
  result.binary = { video: parsedBinary.video };
}
return [result];

// Esperar 10 segundos para que Facebook procese el video
await new Promise(resolve => setTimeout(resolve, 10000));

// Pasar datos del nodo anterior
const extractData = $('Extraer Upload URL').first().json;
return [{ json: extractData }];

const response = $input.first().json;
const videoData = $('Esperar Procesamiento').first().json;
return [{ json: {
  status: response.success ? 'success' : 'error',
  post_id: response.post_id || null,
  video_id: videoData.videoId,
  page_id: videoData.pageId,
  title: videoData.title,
  description: videoData.description,
  file_size_bytes: videoData.fileSize,
  published_at: new Date().toISOString(),
  facebook_response: response,
} }];
